-- Seed idempotente del catalogo Blufin (regenerado desde la BD 2026-06-18).
-- Descripciones ALINEADAS CON INTELISIS (editables en la app; no se generan).
-- Clasificacion por 'producto'. Cada producto+marca+talla+% es un SKU distinto.
on conflict (empresa_id, proveedor, code) do update set
  producto = excluded.producto, marca = excluded.marca, pct = excluded.pct,
  talla = excluded.talla, kg_caja = excluded.kg_caja,
  descripcion = excluded.descripcion, activo = excluded.activo;
